const fs = require('fs');

const raw = $input.first().json;

// Normalise to forward slashes — n8n on Windows emits backslashes
const changedPath = (raw.path || raw.name || '').replace(/\\/g, '/');

if (!changedPath.endsWith('DECISION_LOG.md')) {
  return [];
}

const vault = (process.env.VAULT_PATH || 'C:\\SFV_BLUEPRINT').replace(/\\/g, '/');
const logPath = vault + '/99_INBOX/DECISION_LOG.md';
const content = fs.readFileSync(logPath, 'utf8');

return [{ json: { content, vault } }];

const fs = require('fs');

const { content, vault } = $input.first().json;
const lines = content.split('\n');

// Parse markdown table — skip header, separator, and non-table lines
const flagged = [];
for (const line of lines) {
  const t = line.trim();
  if (!t.startsWith('|')) continue;
  const cols = t.split('|').map(c => c.trim()).filter(Boolean);
  if (cols.length < 5) continue;
  // Skip header row and separator row
  if (cols[0] === 'Timestamp' || cols[0].startsWith('-')) continue;
  const status = cols[4];
  if (status === 'ESCALATED' || status === 'DEFERRED') {
    flagged.push({
      timestamp: cols[0],
      task_id:   cols[1],
      action:    cols[2],
      handler:   cols[3],
      status:    cols[4],
      output:    cols[5] || ''
    });
  }
}

// Nothing to surface — stop execution cleanly
if (flagged.length === 0) return [];

const ts = new Date().toISOString().replace('T', ' ').slice(0, 19);

const tableRows = flagged.map(r =>
  `| ${r.timestamp} | ${r.task_id} | ${r.action} | ${r.handler} | ${r.status} | ${r.output} |`
);

const summary = [
  '---',
  'GENERATED: ' + ts,
  'SOURCE: DECISION_LOG.md',
  'REVIEW_REQUIRED: YES',
  '---',
  '',
  '# ESCALATED / DEFERRED ITEMS',
  '',
  '> These items could not be resolved by Ollama or are queued for n8n Workflow 3 (Tavily).',
  '> Review each row. ESCALATED → read handoff JSON. DEFERRED → build Workflow 3.',
  '',
  '| Timestamp | Task ID | Action | Handler | Status | Output |',
  '|-----------|---------|--------|---------|--------|--------|',
  ...tableRows,
  ''
].join('\n');

const outputDir = vault + '/99_INBOX/OUTPUTS';
fs.mkdirSync(outputDir, { recursive: true });
const outPath = outputDir + '/ESCALATED_ITEMS.md';
fs.writeFileSync(outPath, summary, 'utf8');

return flagged.map(r => ({ json: { ...r, written_to: outPath } }));
